arguments.command:
cd /tmp/sv-727f9aab6a674b0380d436ae2473480b/nuget_dl

LIBPATH="runtime/runtimes/linux-bionic-arm64/native/libcoreclr.so"

# Get ALL dynamic symbols sorted by address, then find what's near our target PCs
echo "=== Finding symbols near tombstone PCs ==="
# Extract symbols into a temp file
readelf --dyn-syms --wide "$LIBPATH" 2>/dev/null | \
  awk '$4 == "FUNC" && $2 != "0000000000000000" {print $2, $3, $8}' | \
  sort > /tmp/syms_sorted.txt

# Target PCs from tombstone
for pc in 003a81f0 003a9244 00298b10 00298c48 0018e3a4 0018df6c; do
  pc_dec=$((16#$pc))
  echo ""
  echo "--- PC 0x$pc ($pc_dec) ---"
  # Find the last symbol with address <= pc
  awk -v target="$pc_dec" '{
    addr = strtonum("0x" $1)
    size = strtonum($2)
    if (addr <= target) {
      last_addr = addr
      last_size = size
      last_name = $3
    }
  }
  END {
    if (last_name != "") {
      offset = target - last_addr
      printf "  Nearest: %s (at 0x%x, size %d, offset +0x%x)\n", last_name, last_addr, last_size, offset
      if (offset < last_size) {
        print "  ** WITHIN function bounds **"
      } else {
        print "  (offset exceeds function size - likely in a non-exported/static function)"
      }
    } else {
      print "  No symbol found before this address"
    }
  }' /tmp/syms_sorted.txt
done

